<script>
let currentRegime='new';
function formatCurrency(n){return'\u20B9'+Math.round(n).toLocaleString('en-IN')}
function setRegime(btn){const el=btn.closest('.toggle-btn')||btn;currentRegime=el.dataset.value;el.parentElement.querySelectorAll('.toggle-btn').forEach(b=>b.classList.remove('active'));el.classList.add('active');const o=currentRegime==='old';document.getElementById('hraRow').style.display=o?'':'none';document.getElementById('metroRow').style.display=o?'':'none';document.getElementById('sec80cGroup').style.display=o?'':'none';document.getElementById('oldDeductionsRow').style.display=o?'':'none';document.getElementById('otherOldRow').style.display=o?'':'none'}
function getVal(id){return parseFloat(document.getElementById(id).value)||0}
function calcHRAExemption(b,h,r,m){if(r===0||h===0)return 0;return Math.min(h,Math.max(r-0.1*b,0),(m?0.5:0.4)*b)}
function calcTaxNewRegime(ti){const s=[{l:400000,r:0},{l:800000,r:0.05},{l:1200000,r:0.10},{l:1600000,r:0.15},{l:2000000,r:0.20},{l:2400000,r:0.25},{l:Infinity,r:0.30}];let t=0,p=0;for(const x of s){if(ti<=p)break;t+=(Math.min(ti,x.l)-p)*x.r;p=x.l}return t}
function calcTaxOldRegime(ti,ag){let s;if(ag==='superSenior')s=[{l:500000,r:0},{l:1000000,r:0.20},{l:Infinity,r:0.30}];else if(ag==='senior')s=[{l:300000,r:0},{l:500000,r:0.05},{l:1000000,r:0.20},{l:Infinity,r:0.30}];else s=[{l:250000,r:0},{l:500000,r:0.05},{l:1000000,r:0.20},{l:Infinity,r:0.30}];let t=0,p=0;for(const x of s){if(ti<=p)break;t+=(Math.min(ti,x.l)-p)*x.r;p=x.l}return t}
function calcSurcharge(tax,inc,reg){if(inc<=5000000)return 0;let r=0;if(reg==='new'){if(inc>20000000)r=0.25;else if(inc>10000000)r=0.15;else r=0.10}else{if(inc>50000000)r=0.37;else if(inc>20000000)r=0.25;else if(inc>10000000)r=0.15;else r=0.10}return tax*r}
function applyRebate87A(tax,ti,reg){if(reg==='new')return ti<=1200000?Math.min(tax,60000):0;return ti<=500000?Math.min(tax,12500):0}
function computeFullTax(gs,reg,ag,d){const sd=reg==='new'?75000:50000;let hra=0,c6=0;if(reg==='old'){hra=d.hraExemption||0;c6=(d.sec80c||0)+(d.sec80d||0)+(d.sec80e||0)+(d.homeLoan||0)+(d.otherExemptions||0)}const nps=d.employerNps||0;let ti=Math.max(gs-sd-hra-c6-nps,0);let tax=reg==='new'?calcTaxNewRegime(ti):calcTaxOldRegime(ti,ag);const reb=applyRebate87A(tax,ti,reg);let tar=Math.max(tax-reb,0);const sur=calcSurcharge(tar,ti,reg);const tps=tar+sur;const ces=tps*0.04;return{stdDed:sd,hraExemption:hra,chapter6A:c6,employerNps:nps,taxableIncome:ti,taxOnIncome:tax,rebate:reb,surcharge:sur,cess:ces,totalTax:Math.round(tps+ces)}}
function calculateTDS(){const gs=getVal('grossSalary');if(gs<=0){alert('Please enter your Gross Annual Salary.');return}const b=getVal('basicSalary')||gs*0.5;const ag=document.getElementById('ageGroup').value;const nps=Math.min(getVal('employerNps'),b*0.10);const im=document.getElementById('isMetro').value==='yes';const d={hraExemption:calcHRAExemption(b,getVal('hraReceived'),getVal('rentPaid'),im),sec80c:Math.min(getVal('sec80c'),150000),sec80d:getVal('sec80d'),sec80e:getVal('sec80e'),homeLoan:Math.min(getVal('homeLoan'),200000),otherExemptions:getVal('otherExemptions'),employerNps:nps};const r=computeFullTax(gs,currentRegime,ag,d);const or=currentRegime==='new'?'old':'new';const ro=computeFullTax(gs,or,ag,d);const mt=Math.round(r.totalTax/12);const ef=gs>0?((r.totalTax/gs)*100).toFixed(1):'0.0';document.getElementById('resAnnualTax').textContent=formatCurrency(r.totalTax);document.getElementById('resMonthlyTDS').textContent=formatCurrency(mt);document.getElementById('resTaxableIncome').textContent=formatCurrency(r.taxableIncome);document.getElementById('resEffRate').textContent=ef+'%';document.getElementById('resInHand').textContent=formatCurrency(gs-r.totalTax);document.getElementById('brkGross').textContent=formatCurrency(gs);document.getElementById('brkStdDed').textContent='\u2212'+formatCurrency(r.stdDed);document.getElementById('brkNps').textContent='\u2212'+formatCurrency(r.employerNps);document.getElementById('brkTaxable').textContent=formatCurrency(r.taxableIncome);document.getElementById('brkTaxOnIncome').textContent=formatCurrency(r.taxOnIncome);document.getElementById('brkRebate').textContent='\u2212'+formatCurrency(r.rebate);document.getElementById('brkSurcharge').textContent=formatCurrency(r.surcharge);document.getElementById('brkCess').textContent=formatCurrency(Math.round(r.cess));document.getElementById('brkTotal').textContent=formatCurrency(r.totalTax);if(currentRegime==='old'){document.getElementById('brkHraRow').style.display='';document.getElementById('brkHra').textContent='\u2212'+formatCurrency(r.hraExemption);document.getElementById('brkChap6Row').style.display='';document.getElementById('brkChap6').textContent='\u2212'+formatCurrency(r.chapter6A)}else{document.getElementById('brkHraRow').style.display='none';document.getElementById('brkChap6Row').style.display='none'}const nt=currentRegime==='new'?r.totalTax:ro.totalTax;const ot=currentRegime==='old'?r.totalTax:ro.totalTax;document.getElementById('cmpNewTax').textContent=formatCurrency(nt);document.getElementById('cmpOldTax').textContent=formatCurrency(ot);const cn=document.getElementById('compareNew'),co=document.getElementById('compareOld');cn.classList.remove('recommended');co.classList.remove('recommended');const sb=document.getElementById('savingsBadge');sb.style.background='';if(nt<ot){cn.classList.add('recommended');sb.textContent='\u2713 New Regime saves you '+formatCurrency(ot-nt)+'/year';sb.style.display='inline-block'}else if(ot<nt){co.classList.add('recommended');sb.textContent='\u2713 Old Regime saves you '+formatCurrency(nt-ot)+'/year';sb.style.display='inline-block'}else{sb.textContent='Both regimes result in the same tax';sb.style.display='inline-block';sb.style.background='var(--text-muted)'}document.getElementById('resultSection').classList.add('visible');document.getElementById('resultSection').scrollIntoView({behavior:'smooth',block:'start'})}
function resetCalc(){document.querySelectorAll('.calc-card input[type="number"]').forEach(i=>i.value='');document.getElementById('ageGroup').selectedIndex=0;document.getElementById('isMetro').selectedIndex=0;document.getElementById('resultSection').classList.remove('visible');const sb=document.getElementById('savingsBadge');sb.style.display='none';sb.style.background=''}
document.getElementById('grossSalary').addEventListener('keydown',function(e){if(e.key==='Enter')calculateTDS()});
function toggleFaq(e){const btn=e.closest?e.closest('.faq-question')||e:e;const item=btn.closest('.faq-item');if(!item)return;const isOpen=item.classList.contains('open');document.querySelectorAll('.faq-item').forEach(i=>i.classList.remove('open'));if(!isOpen)item.classList.add('open')}
const sections=document.querySelectorAll('[id]'),navLinks=document.querySelectorAll('.toc-nav a');window.addEventListener('scroll',()=>{let c='';sections.forEach(s=>{if(pageYOffset>=s.offsetTop-80)c=s.getAttribute('id')});navLinks.forEach(l=>{l.classList.toggle('active',l.getAttribute('href')==='#'+c)})});
</script>
